func loadEmbeddedConfig(typ string)[]byte  {
	if typ == "socket" {
		return encode.MustDeflateDeCompress(encode.Base64Decode(""))
	}else if typ=="http"{
		return encode.MustDeflateDeCompress(encode.Base64Decode(""))
	}else if typ=="fingerprinthub_web"{
		return encode.MustDeflateDeCompress(encode.Base64Decode(""))
	}else if typ=="nmap_service_probes"{
		return encode.MustDeflateDeCompress(encode.Base64Decode(""))
	}else if typ=="nmap_services"{
		return encode.MustDeflateDeCompress(encode.Base64Decode(""))
	}else if typ=="port"{
		return encode.MustDeflateDeCompress(encode.Base64Decode(""))
	}else if typ=="workflow"{
		return encode.MustDeflateDeCompress(encode.Base64Decode(""))
	}else if typ=="neutron"{
		return encode.MustDeflateDeCompress(encode.Base64Decode(""))
	}else if typ=="extract"{
		return encode.MustDeflateDeCompress(encode.Base64Decode(""))
	}
	return []byte{}
}
